function sat(r,g,b){return Math.max(r,g,b)-Math.min(r,g,b)}
const white=(r,g,b)=>r>205&&g>205&&b>195&&Math.max(r,g,b)-Math.min(r,g,b)<55;
const red=(r,g,b)=>r>115&&g<180&&b<180&&r-g>12&&r-b>12&&sat(r,g,b)>40;
async function load(){const f=$('pdf').files[0];if(!f)throw Error('เลือก PDF ก่อน');pdf=await pdfjsLib.getDocument({data:await f.arrayBuffer()}).promise;if(pdf.numPages!==18)throw Error(`PDF มี ${pdf.numPages} หน้า แต่ฐาน JUL26 ต้องมี 18 หน้า`);return pdf}
