function comps(c,pred,roi,step=3,minA=70){const x0=Math.max(0,Math.floor(roi.x)),y0=Math.max(0,Math.floor(roi.y)),w=Math.max(1,Math.min(c.width-x0,Math.floor(roi.w))),h=Math.max(1,Math.min(c.height-y0,Math.floor(roi.h))),d=c.getContext('2d',{willReadFrequently:true}).getImageData(x0,y0,w,h).data,sw=Math.max(1,Math.floor(w/step)),sh=Math.max(1,Math.floor(h/step)),m=new Uint8Array(sw*sh),seen=new Uint8Array(sw*sh);for(let y=0;y<sh;y++)for(let x=0;x<sw;x++){const px=Math.min(w-1,x*step),py=Math.min(h-1,y*step),i=(py*w+px)*4;if(pred(d[i],d[i+1],d[i+2]))m[y*sw+x]=1}const out=[],dirs=[[1,0],[-1,0],[0,1],[0,-1]];for(let y=0;y<sh;y++)for(let x=0;x<sw;x++){const idx=y*sw+x;if(!m[idx]||seen[idx])continue;const q=[[x,y]];let qi=0,a=0,minX=x,minY=y,maxX=x,maxY=y;seen[idx]=1;while(qi<q.length){const [cx,cy]=q[qi++];a++;if(cx<minX)minX=cx;if(cy<minY)minY=cy;if(cx>maxX)maxX=cx;if(cy>maxY)maxY=cy;for(const[dx,dy]of dirs){const nx=cx+dx,ny=cy+dy;if(nx<0||ny<0||nx>=sw||ny>=sh)continue;const ni=ny*sw+nx;if(m[ni]&&!seen[ni]){seen[ni]=1;q.push([nx,ny])}}}if(a>=minA)out.push({x:x0+minX*step,y:y0+minY*step,w:(maxX-minX+1)*step,h:(maxY-minY+1)*step,area:a})}return out}
