function canvasDataUrl(c,quality=.88){return c.toDataURL('image/webp',quality)}
async function runPool(tasks,workers,fn){let next=0,done=0;await Promise.all(workers.map(async worker=>{while(true){const i=next++;if(i>=tasks.length)return;await fn(tasks[i],worker,i);done++;bar(done,tasks.length)}}))}
function renderPreview(it){if(crops.children.length>=60)return;const box=document.createElement('div'),img=new Image(),meta=document.createElement('div');box.className='box '+(it.pass?'pass':'fail')+(it.detectionStatus==='need_review'?' review':'');img.src=it.dataUrl;meta.className='meta';meta.innerHTML=`<span class="tag ${it.pass?'green':'redtag'}">${it.pass?'GRID PASS':'GRID FAIL'}</span><span class="tag ${it.detectionStatus==='auto_ok'?'green':'orange'}">${it.detectionStatus==='auto_ok'?'AUTO OK':'ต้องตรวจ'}</span><span class="tag blue">${it.fileName}</span><div class="ocr"><b>ผลไทย:</b> ${it.detectedFunctionLabel||'-'}</div><div class="ocr"><b>OCR ดิบ:</b> ${it.ocr.raw||'-'}</div>`;box.append(img,meta);crops.appendChild(box)}
async function detect(){if(!pdf)await load();items=[];crops.textContent='';logEl.textContent='';const counts={},pending=[];for(let p=1;p<=pdf.numPages;p++){const cls=PAGES[p];counts[cls]=counts[cls]||0;const pg=await render(p,1.7),boxes=stableGridBoxes(pg);st(`หน้า ${p}: พบ ${boxes.length} ใบ`);for(const r of boxes){counts[cls]++;const no=counts[cls],cardId=`${$('month').value.trim().toUpperCase()}-${cls}-${String(no).padStart(3,'0')}`,fileName=`${cls}-${String(no).padStart(3,'0')}-p${String(p).padStart(2,'0')}.webp`,card=crop(pg,r,0),benefitBox=findBenefitBox(card),benefit=crop(card,benefitBox,0),extra=no>DB[cls];pending.push({cls,no,page:p,cardId,fileName,card,benefit,benefitBox,extra})}pg.width=1;pg.height=1}for(const cls of Object.keys(DB)){const found=counts[cls]||0;log(`${cls}: ${found}/${DB[cls]}`,found===DB[cls]?'ok':'bad')}const countOk=Object.keys(DB).every(k=>(counts[k]||0)===DB[k])&&pending.length===212;if(!countOk)throw Error('จำนวนการ์ดไม่ตรงฐาน 212 — ปิดการอัปโหลดเพื่อกันสลับใบ');const workers=await createOcrWorkers();st('กำลังอ่านข้อความโปร...');await runPool(pending,workers,async(it,worker)=>{const ocr=await recognize(worker,it.benefit),pass=!it.extra&&!!it.card&&!!it.benefit,detectedFunctionLabel=ocr.label,detectionStatus=pass&&ocr.valid?'auto_ok':'need_review',dataUrl=canvasDataUrl(it.card,.88);items.push({...it,ocr,pass,detectedFunctionLabel,detectionStatus,dataUrl,uploadable:pass&&ocr.valid});it.card.width=1;it.card.height=1;it.benefit.width=1;it.benefit.height=1;renderPreview(items.at(-1))});items.sort((a,b)=>a.page-b.page||a.no-b.no);setSum();st(`เสร็จ: ${items.length} ใบ | AUTO OK ${items.filter(x=>x.detectionStatus==='auto_ok').length} | ต้องตรวจ ${items.filter(x=>x.detectionStatus==='need_review').length}`);for(const w of ocrWorkers)await w.terminate();ocrWorkers=[]}
async function postBatch(cards,key,month){const started=performance.now(),r=await fetch(ENDPOINT,{method:'POST',headers:{'Content-Type':'application/json','x-promo-admin-key':key},body:JSON.stringify({action:'batch_upload',promo_month_id:month,cards:cards.map(it=>({file_name:it.fileName,data_url:it.dataUrl,benefit_text:it.detectedFunctionLabel,detected_function_label:it.detectedFunctionLabel,benefit_confidence:it.ocr.confidence,benefit_box:it.benefitBox,detection_status:it.detectionStatus,detection_method:'blue_grid_lock_v3_redbox_structured'}))})}),j=await r.json();if(!r.ok||!j.ok)throw Error((j.error||'upload_failed')+(j.detail?': '+j.detail:''));return{...j,client_ms:Math.round(performance.now()-started)}}
async function upload(){const key=$('key').value.trim(),month=$('month').value.trim().toUpperCase();if(!key)return alert('ใส่รหัสก่อน');if(items.length!==212)return alert('ต้องตรวจครบ 212 ใบก่อน');const up=items.filter(x=>x.uploadable);if(up.length!==212)return alert(`ยังมีรายการต้องตรวจ ${212-up.length} ใบ — V2 ไม่อัปโหลดข้อมูลไม่ครบ`);$('upload').disabled=true;const size=Number($('batch').value),conc=Number($('concurrency').value),batches=[];for(let i=0;i<up.length;i+=size)batches.push(up.slice(i,i+size));let next=0,done=0,ok=0,fail=0;const t0=performance.now();await Promise.all(Array.from({length:conc},async()=>{while(true){const i=next++;if(i>=batches.length)return;try{const j=await postBatch(batches[i],key,month);ok+=j.uploaded||batches[i].length;log(`✓ Batch ${i+1}/${batches.length}: ${j.uploaded} ใบ | server ${j.total_ms} ms | client ${j.client_ms} ms`,'ok')}catch(e){fail+=batches[i].length;log(`✗ Batch ${i+1}: ${e.message||e}`,'bad')}done++;bar(done,batches.length)}}));const sec=((performance.now()-t0)/1000).toFixed(1);st(`อัปโหลดเสร็จ ${ok}/212 | ล้มเหลว ${fail} | ${sec} วินาที`);$('upload').disabled=false}
async function clearAll(){for(const w of ocrWorkers)try{await w.terminate()}catch{}ocrWorkers=[];pdf=null;items=[];crops.textContent='';logEl.textContent='';bar(0,0);setSum();st('ล้างแล้ว')}
$('detect').onclick=async()=>{try{if(!pdf)await load();await detect()}catch(e){log('ERROR: '+(e.message||e),'bad');st('ตรวจไม่สำเร็จ')}};
$('upload').onclick=upload;$('clear').onclick=clearAll;setSum();
